"use client"

import useSWR from "swr"
import { ScrollReveal, StaggerContainer, StaggerItem, Parallax } from "@/components/scroll-animations"
import { Brain, Code, Database, Cpu, GraduationCap, Award, Terminal, Sparkles } from "lucide-react"
import { Spinner } from "@/components/ui/spinner"
import type { Profile, Project, Research } from "@/lib/models"

const iconMap: Record<string, React.ElementType> = {
  Brain, Code, Database, Cpu, GraduationCap, Award, Terminal, Sparkles
}

const fetcher = (url: string) => fetch(url).then(res => res.json())

export function AboutSection() {
  const { data: profile, isLoading: isProfileLoading } = useSWR<Profile>("/api/profile", fetcher, { revalidateOnFocus: false })
  const { data: projects, isLoading: isProjectsLoading } = useSWR<Project[]>("/api/projects", fetcher, { revalidateOnFocus: false })
  const { data: research, isLoading: isResearchLoading } = useSWR<Research[]>("/api/research", fetcher, { revalidateOnFocus: false })

  if (isProfileLoading || isProjectsLoading || isResearchLoading) {
    return (
      <section id="about" className="py-32 px-6 relative flex justify-center">
        <Spinner className="w-8 h-8 text-primary" />
      </section>
    )
  }

  const bio = profile?.bio && profile.bio.length > 0 ? profile.bio : [
    "I am an AI/ML Researcher and Engineer dedicated to building next-generation artificial intelligence systems.",
    "My passion lies in bridging the gap between theoretical research and practical, real-world implementations."
  ]

  // Calculate dynamic stats from projects and research
  const mlProjects = projects?.filter(p => p.categories?.includes("Machine Learning") || p.categories?.includes("Deep Learning") || p.technologies?.includes("PyTorch"))?.length || 0
  const backendProjects = projects?.filter(p => p.categories?.includes("Backend") || p.categories?.includes("Distributed Systems"))?.length || 0
  const totalProjects = projects?.length || 1

  const researchCount = research?.length || 0

  // Derived skills
  const derivedSkills = [
    { name: "Deep Learning & AI", icon: "Brain", level: Math.min(100, 50 + (mlProjects * 10)) },
    { name: "Backend & Systems", icon: "Database", level: Math.min(100, 50 + (backendProjects * 10)) },
    { name: "Software Engineering", icon: "Code", level: Math.min(100, 60 + (totalProjects * 5)) },
    { name: "Research & Analysis", icon: "Terminal", level: Math.min(100, 60 + (researchCount * 15)) },
  ]

  const highlights = profile?.highlights && profile.highlights.length > 0 ? profile.highlights : [
    { icon: "GraduationCap", label: "University", value: "Computer Science" },
    { icon: "Award", label: "Experience", value: "3+ Years" },
    { icon: "Brain", label: "Models Built", value: `${totalProjects}+` },
    { icon: "Database", label: "Research", value: `${researchCount}+` },
  ]

  return (
    <section id="about" className="py-32 px-6 relative border-t border-primary/10">
      <div className="max-w-6xl mx-auto">
        <ScrollReveal>
          <div className="text-center mb-16">
            <h2 className="text-4xl md:text-5xl font-bold mb-4 font-mono">
              About <span className="text-primary glow-text">Me</span>
            </h2>
            <p className="text-muted-foreground text-lg max-w-2xl mx-auto font-mono">
              {profile?.title || "Building intelligent systems and exploring the frontiers of AI"}
            </p>
          </div>
        </ScrollReveal>
        
        <div className="grid lg:grid-cols-2 gap-16 items-center">
          <Parallax offset={30}>
            <ScrollReveal delay={0.2}>
              <div className="space-y-8">
                <div className="relative">
                  <div className="absolute -left-4 top-0 bottom-0 w-1 bg-gradient-to-b from-primary via-accent to-transparent rounded-full" />
                  <div className="space-y-6 text-lg md:text-xl text-muted-foreground leading-relaxed">
                    {bio.map((paragraph, idx) => (
                      <p key={idx} className="relative">
                        <span className="text-primary/40 font-serif italic text-4xl absolute -left-10 -top-4 opacity-20">"</span>
                        {paragraph}
                      </p>
                    ))}
                  </div>
                </div>
                
                {/* Skill bars */}
                <div className="space-y-4 pt-6">
                  <h3 className="font-mono text-primary mb-4 text-sm uppercase tracking-widest flex items-center gap-2">
                    <Sparkles className="w-4 h-4" />
                    system_capabilities
                  </h3>
                  {derivedSkills.map((skill, idx) => (
                    <SkillBar key={skill.name} skill={skill} delay={idx * 0.1} />
                  ))}
                </div>
              </div>
            </ScrollReveal>
          </Parallax>
          
          <StaggerContainer className="grid grid-cols-2 gap-6" staggerDelay={0.15}>
            {highlights.map((item) => {
              const Icon = iconMap[item.icon as string] || Code;
              return (
                <StaggerItem key={item.label}>
                  <div className="p-8 rounded-3xl border border-primary/20 bg-card/20 backdrop-blur-xl hover:border-primary/50 transition-all hover:shadow-[0_0_30px_rgba(0,255,65,0.1)] group h-full flex flex-col justify-center items-center text-center relative overflow-hidden">
                    <div className="absolute top-0 right-0 w-16 h-16 bg-primary/5 rounded-bl-full -mr-8 -mt-8 transition-all group-hover:scale-150" />
                    
                    <div className="w-16 h-16 rounded-2xl bg-primary/10 flex items-center justify-center mb-6 group-hover:bg-primary/20 group-hover:scale-110 transition-all shadow-[0_0_15px_rgba(0,255,65,0.1)]">
                      <Icon className="w-8 h-8 text-primary group-hover:drop-shadow-[0_0_8px_rgba(0,255,65,0.8)]" />
                    </div>
                    <div className="text-3xl md:text-4xl font-bold text-foreground mb-2 font-mono tracking-tighter">{item.value}</div>
                    <div className="text-xs text-muted-foreground font-mono uppercase tracking-[0.2em]">{item.label}</div>
                  </div>
                </StaggerItem>
              )
            })}
          </StaggerContainer>
        </div>
      </div>
    </section>
  )
}

function SkillBar({ skill, delay }: { skill: any; delay: number }) {
  const Icon = iconMap[skill.icon as string] || Code;
  return (
    <ScrollReveal delay={delay}>
      <div className="space-y-3">
        <div className="flex items-center justify-between font-mono">
          <div className="flex items-center gap-3">
            <div className="p-1.5 rounded-md bg-muted/50 border border-primary/10">
              <Icon className="w-4 h-4 text-primary" />
            </div>
            <span className="font-medium text-foreground text-sm">{skill.name}</span>
          </div>
          <span className="text-xs font-bold text-primary bg-primary/10 px-2 py-0.5 rounded">{skill.level}%</span>
        </div>
        <div className="h-1.5 rounded-full bg-muted/30 overflow-hidden border border-primary/5 p-[1px]">
          <div
            className="h-full rounded-full bg-gradient-to-r from-primary via-primary/80 to-accent relative"
            style={{ width: `${skill.level}%` }}
          >
            <div className="absolute top-0 right-0 bottom-0 w-8 bg-white/20 blur-[4px] animate-pulse" />
          </div>
        </div>
      </div>
    </ScrollReveal>
  )
}
